create table dirkspzm32.isi_artikel_lieferant (
    sid                varchar2(2 char) default '01' not null enable,
    firma_nr           number default 1 not null enable,
    lieferant_nr       varchar2(20 char) not null enable,
    artikel_id         number(*, 0) not null enable,
    art_nr_lieferant   varchar2(50 char),
    art_nr_hersteller  varchar2(50 char),
    art_text1          varchar2(255 char),
    art_text2          varchar2(255 char),
    art_text3          varchar2(255 char),
    info               varchar2(2000 char),
    lhm_name           varchar2(50 char),
    lhm_menge          number(*, 3),
    lhm_gewicht_kg     number(*, 6),
    lhm_ean            varchar2(15 char),
    lte_name           varchar2(22 char),
    lte_menge          number(*, 3),
    lte_gewicht_kg     number(*, 6),
    lte_ean            varchar2(15 char),
    art_ean_lieferant  varchar2(15 char),
    listen_preis       number(*, 5),
    eink_rabatt_faktor number(*, 6),
    eink_preis         number(*, 5),
    stand_lief         varchar2(1 char) default 'F'
);

alter table dirkspzm32.isi_artikel_lieferant
    add constraint pk_artikel_lieferant primary key ( artikel_id,
                                                      lieferant_nr )
        using index enable;

alter table dirkspzm32.isi_artikel_lieferant
    add constraint uk_artikel_lieferant unique ( lieferant_nr,
                                                 art_nr_lieferant )
        using index enable;


